28	func parseFromModel(ctx context.Context, name model.Name, fn func(api.ProgressResponse)) (layers []*layerGGML, err error) {
29		m, err := manifest.ParseNamedManifest(name)
30		switch {
31		case errors.Is(err, os.ErrNotExist):
32			if err := PullModel(ctx, name.String(), &registryOptions{}, fn); err != nil {
33				return nil, err
34			}
35	
36			m, err = manifest.ParseNamedManifest(name)
37			if err != nil {
38				return nil, err
39			}
40		case err != nil:
41			return nil, err
42		}
43	
44		for _, layer := range m.Layers {
45			layer, err := manifest.NewLayerFromLayer(layer.Digest, layer.MediaType, name.DisplayShortest())
46			if err != nil {
47				return nil, err
48			}
49	
50			switch layer.MediaType {
51			case "application/vnd.ollama.image.model",
52				"application/vnd.ollama.image.projector",
53				"application/vnd.ollama.image.adapter":
54				blobpath, err := manifest.BlobsPath(layer.Digest)
55				if err != nil {
56					return nil, err
57				}
58	
59				blob, err := os.Open(blobpath)
60				if err != nil {
61					return nil, err
62				}
63				defer blob.Close()
64	
65				f, err := ggml.Decode(blob, -1)
66				if err != nil {
67					return nil, err
68				}
69	
70				layers = append(layers, &layerGGML{layer, f})
71			default:
72				layers = append(layers, &layerGGML{layer, nil})
73			}
74		}
75	
76		return layers, nil
77	}
