79	func detectChatTemplate(layers []*layerGGML) ([]*layerGGML, error) {
80		for _, layer := range layers {
81			if s := layer.GGML.KV().ChatTemplate(); s != "" {
82				if t, err := template.Named(s); err != nil {
83					slog.Debug("template detection", "error", err, "template", s)
84				} else {
85					layer, err := manifest.NewLayer(t.Reader(), "application/vnd.ollama.image.template")
86					if err != nil {
87						return nil, err
88					}
89	
90					layer.Status = fmt.Sprintf("using autodetected template %s", t.Name)
91					layers = append(layers, &layerGGML{layer, nil})
92	
93					if t.Parameters != nil {
94						var b bytes.Buffer
95						if err := json.NewEncoder(&b).Encode(t.Parameters); err != nil {
96							return nil, err
97						}
98	
99						layer, err := manifest.NewLayer(&b, "application/vnd.ollama.image.params")
100						if err != nil {
101							return nil, err
102						}
103	
104						layers = append(layers, &layerGGML{layer, nil})
105					}
106				}
107			}
108		}
109	
110		return layers, nil
111	}
