113	func detectContentType(r io.Reader) (string, error) {
114		var b bytes.Buffer
115		if _, err := io.Copy(&b, r); err != nil {
116			return "", err
117		}
118	
119		if contentType := ggml.DetectContentType(b.Bytes()); contentType != "" {
120			return contentType, nil
121		}
122	
123		if contentType := http.DetectContentType(b.Bytes()); contentType != "application/octet-stream" {
124			return contentType, nil
125		}
126	
127		return "unknown", nil
128	}
